screens.custom_css:
.row[custom-css-selector="center-grid"] > .col-sm-12 {
  display: flex !important;
  justify-content: center !important; /* centra horizontal */
  align-items: center !important;      /* centra vertical (si hay altura) */
}

/* Evita ancho completo del botón si el tema lo impone */
.row[custom-css-selector="center-grid"] > .col-sm-12 .form-group > .btn,
.row[custom-css-selector="center-grid"] > .col-sm-12 .form-group > button {
  width: max-content !important; /* o auto */
  margin: 0 auto !important;
  align-self: center !important;
}

:root {
  --accent: #2167AE;     /* Azul institucional */
  --red: #b01200;    /* Verde de confirmación */
  --bg: #f7f9fc;
  --card: #ffffff;
  --border: #e5e7eb;
  --shadow: 0 8px 20px rgba(0,0,0,0.08);
}

/* Forzamos todo el bloque */
[selector="completado-screen"] {
  /* min-height: 80vh;*/
  display: grid;
  place-items: center;
  padding: 24px;
  background: var(--bg);
  font-family: "Segoe UI", Roboto, Arial, sans-serif !important;
  color: var(--accent) !important;
}

[selector="completado-screen"] .wrap, 
[selector="completado-screen"] .wrap * {
  font-family: "Segoe UI", Roboto, Arial, sans-serif !important;
  color: var(--accent) !important;
}

[selector="completado-screen"] .wrap {
  /*width: min(600px, 100%);*/
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 16px;
  box-shadow: var(--shadow);
  padding: clamp(28px, 4vw, 44px);
  text-align: center;
  animation: fadeIn .6s ease both;
}

/* Ícono check */
[selector="completado-screen"] .wrap::before {
  content: "\f00d"; /* fa-check */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  display: block;
  font-size: 3rem;
  color: var(--red) !important;
  margin-bottom: 14px;
  line-height: 1;
}

/* Badge para número de caso */
[selector="completado-screen"] .numero-caso {
  display: inline-block;
  margin: 14px 0 10px;
  font-weight: 700;
  font-size: 1.2rem;
  letter-spacing: 0.3px;
  padding: 8px 16px;
  border-radius: 999px;
  background: rgba(33,103,174,0.1);
  border: 1px solid var(--accent);
  color: var(--accent) !important;
}

/* Nota final */
[selector="completado-screen"] .nota {
  margin-top: 18px;
  font-size: 0.95rem;
  background: rgba(33,103,174,0.05);
  border: 1px dashed var(--accent);
  padding: 12px 16px;
  border-radius: 12px;
  color: var(--accent) !important;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* Logo institucional */
[selector="logo-completado"] {
  display: block;
  margin: 0 auto 20px auto;
  max-width: 160px;
  height: auto;
}
